ee:variables.ee:set-variable:
%dw 2.0
output application/json

var transactionType = attributes.queryParams.transactionType
var purpose = attributes.queryParams.purpose


var poNumber =
    (attributes.queryParams.businesskey default "")
        splitBy ","
        map (trim($))
        filter ($ != "")
        distinctBy $

var routingConfig = {
    purchaseOrder: {
        total: {
            view: Mule::p('viewNames.purchaseOrderOutbound'),
            queryParams: {

            }
        },
        outbound: {
            view: Mule::p('viewNames.purchaseOrderOutbound'),
            queryParams: {
                "\$filter": (poNumber map ("po_no eq " ++ $)) joinBy " or "
            }
        }
    },

    purchaseOrderAck: {
        validation: {
            view: Mule::p('viewNames.purchaseOrderAckInbound'),
            queryParams: {
                "\$filter": (poNumber map ("po_no eq " ++ $)) joinBy " or "
            }
        }
    },

    purchaseOrderInvoice: {
        validation: {
            view: Mule::p('viewNames.purchaseOrderInvoiceInbound'),
            queryParams: {
                "\$filter": (poNumber map ("po_no eq " ++ $)) joinBy " or "
            }
        }
    },

    purchaseOrderShipment: {
        validation: {
            view: "PURCHASE_ORDER_SHIPMENT_VALIDATION_VIEW",
            queryParams: {
                "\$filter": (poNumber map ("po_no eq " ++ $)) joinBy " or "
            }
        },
        total: {
            view: "PURCHASE_ORDER_SHIPMENT_TOTAL_VIEW",
            queryParams: {
                "\$filter": (poNumber map ("po_no eq " ++ $)) joinBy " or "
            }
        }
    },

    salesOrder: {
        validation: {
            view: "SALES_ORDER_VALIDATION_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        outbound: {
            view: "SALES_ORDER_OUTBOUND_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        total: {
            view: "SALES_ORDER_TOTAL_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        }
    },

    salesOrderAck: {
        validation: {
            view: "SALES_ORDER_ACK_VALIDATION_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        outbound: {
            view: "SALES_ORDER_ACK_OUTBOUND_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        total: {
            view: "SALES_ORDER_ACK_TOTAL_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        }
    },

    salesOrderInvoice: {
        validation: {
            view: "SALES_ORDER_INVOICE_VALIDATION_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        outbound: {
            view: "SALES_ORDER_INVOICE_OUTBOUND_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        total: {
            view: "SALES_ORDER_INVOICE_TOTAL_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        }
    },

    salesOrderShipment: {
        validation: {
            view: "SALES_ORDER_SHIPMENT_VALIDATION_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        outbound: {
            view: "SALES_ORDER_SHIPMENT_OUTBOUND_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        },
        total: {
            view: "SALES_ORDER_SHIPMENT_TOTAL_VIEW",
            queryParams: {
                param1: "VALUE_PLACEHOLDER"
            }
        }
    }
}

// Safe selection (prevents null crash)
var selectedConfig =
    (routingConfig[transactionType] default {})[purpose] default {}

---

{
    method: Mule::p('p21.request.method.OData'),
    host: Mule::p('p21.request.host'),
    port: Mule::p('p21.request.port'),
    basePath: Mule::p('p21.request.basePath.Odata'),

    path: "/" ++ (selectedConfig.view default ""),

    headers: {
        Authorization: "Bearer "++ (vars.accessToken default "") ,
        "Content-Type": "application/json"
    },
    retryMechanism: {
    	"maxConcurrency": Mule::p('p21.request.reconnection.maxConcurrency.OData'),
    	"retries":  Mule::p('p21.request.reconnection.retries.OData')
    },
    queryParams: selectedConfig.queryParams default {},

    uriParams: {},

    body: {   }
}
